function readImage(input){return new Promise((resolve,reject)=>{const file=input.files[0];if(!file)return resolve("");if(file.size>2*1024*1024)return reject(new Error("Bild ist größer als 2 MB"));const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=()=>reject(new Error("Bild konnte nicht gelesen werden"));reader.readAsDataURL(file)})}

let updatePollTimer;
