async function loadHosts() {
  const [data, certificateData] = await Promise.all([api("/api/proxy-hosts"), api("/api/certificates")]);
  const hostBadge = document.querySelector("#hostCountBadge");
  if (hostBadge) hostBadge.textContent = data.items.length;
  const certificateSelect = document.querySelector("#certificateSelect");
  const issuedCertificates = certificateData.items.filter(certificate => certificate.status === "issued");
  certificateSelect.innerHTML = '<option value="">– Kein Zertifikat gewählt –</option>' + issuedCertificates.map(certificate => `<option value="${certificate.id}">${escapeHtml(certificate.domain)} · gültig${certificate.expires_at ? ` bis ${new Date(certificate.expires_at * 1000).toLocaleDateString("de-DE")}` : ""}</option>`).join("");
  const host = data.items[0];
  if (!host) { state.hostId = null; certificateSelect.value = ""; document.querySelector("#healthPath").value = "/"; document.querySelector(".title-line h1").textContent = "Neuer Proxy Host"; renderTargets(); updateOverviewStrip().catch(()=>{}); return; }
  state.hostId = host.id; document.querySelector("#domain").value = host.domain; document.querySelector("#port").value = host.port;
  document.querySelector("#scheme").value = host.scheme; document.querySelector("#strategy").value = host.strategy;
  document.querySelector("#websocket").checked = Boolean(host.websocket); document.querySelector("#sslEnabled").checked = Boolean(host.ssl_enabled);
  certificateSelect.value = host.certificate_id ? String(host.certificate_id) : "";
  document.querySelector("#healthPath").value = host.targets[0]?.health_path || "/";
  document.querySelector(".title-line h1").textContent = host.domain;
  state.targets = host.targets.map(target => ({ ...target, family: target.family === "hostname" ? "Hostname" : target.family, mode: target.mode === "backup" ? "Backup" : target.mode === "off" ? "Aus" : "Aktiv", healthy: target.healthy !== 0 }));
  renderTargets();
  updateOverviewStrip().catch(()=>{});
}

