async function showHostOverview() {
  const [hostData, certificateData] = await Promise.all([api("/api/proxy-hosts"), api("/api/certificates")]);
  const dashboard = document.querySelector("#realDashboard"); if (dashboard) dashboard.hidden = true;
  const view = document.querySelector("main>.content:not(#realDashboard)"); view.hidden = false; view.dataset.view = "host-list";
  document.querySelectorAll(".sidebar nav a").forEach(link => link.classList.toggle("active", link.id === "proxyHostsLink"));
  document.querySelector(".breadcrumbs span").textContent = "Proxy Hosts"; document.querySelector(".breadcrumbs strong").textContent = "Übersicht";
  document.querySelector("#hostCountBadge").textContent = hostData.items.length;
  view.innerHTML = `<div class="host-overview-head"><div><h1>Proxy Hosts</h1><p>Alle Domains, Ziele und Zertifikate auf einen Blick.</p></div><button class="button primary" id="newHostModal">＋ Neuer Proxy Host</button></div><div class="host-overview-list">${hostData.items.map(host => { const certificate=certificateData.items.find(item=>item.id===host.certificate_id); const healthy=host.targets.filter(target=>target.healthy===1).length; return `<article class="host-overview-row"><div><strong>${escapeHtml(host.domain)}</strong><small>${escapeHtml(host.scheme)} · Port ${host.port}</small></div><span class="tag">${host.enabled?"● Aktiv":"Deaktiviert"}</span><span>${healthy} / ${host.targets.length} gesund</span><span class="tag">${certificate?`SSL · ${escapeHtml(certificate.domain)}`:host.ssl_enabled?"SSL ohne Zertifikat":"Kein SSL"}</span><button class="button host-edit" data-host-id="${host.id}">Bearbeiten</button></article>` }).join("") || '<div class="card empty-state">Noch keine Proxy Hosts vorhanden.</div>'}</div>`;
  document.querySelector("#newHostModal").onclick = () => openHostModal(null, certificateData.items);
  view.querySelectorAll(".host-edit").forEach(button => button.onclick = () => openHostModal(hostData.items.find(host => host.id === Number(button.dataset.hostId)), certificateData.items));
}

function openHostModal(host, certificates) {
  const dialog = document.querySelector("#hostDialog"), form = document.querySelector("#hostModalForm");
  document.querySelector("#hostDialogTitle").textContent = host ? host.domain : "Neuer Proxy Host";
  const targets = host?.targets?.length ? host.targets : [{address:"",family:"IPv4",weight:100,mode:"active",health_path:"/"}];
  form.innerHTML = `<div class="host-modal-grid"><label class="wide"><span>Domainname</span><input name="domain" value="${escapeHtml(host?.domain||"")}" placeholder="app.example.com" required></label><label><span>Schema</span><select name="scheme"><option ${host?.scheme!=="https"?"selected":""}>http</option><option ${host?.scheme==="https"?"selected":""}>https</option></select></label><label><span>Port</span><input name="port" type="number" min="1" max="65535" value="${host?.port||80}" required></label><label><span>Strategie</span><select name="strategy"><option value="least_conn" ${host?.strategy!=="round_robin"&&host?.strategy!=="ip_hash"?"selected":""}>Wenigste Verbindungen</option><option value="round_robin" ${host?.strategy==="round_robin"?"selected":""}>Round Robin</option><option value="ip_hash" ${host?.strategy==="ip_hash"?"selected":""}>Client-IP</option></select></label><label class="wide"><span>SSL-Zertifikat</span><select name="certificate_id"><option value="">– Kein Zertifikat –</option>${certificates.filter(certificate=>certificate.status==="issued").map(certificate=>`<option value="${certificate.id}" ${certificate.id===host?.certificate_id?"selected":""}>${escapeHtml(certificate.domain)} · Gültig</option>`).join("")}</select></label><label class="wide"><span>Healthcheck-Pfad</span><input name="health_path" value="${escapeHtml(targets[0]?.health_path||"/")}" placeholder="/"></label></div><div class="host-modal-options"><label><input name="websocket" type="checkbox" ${host?.websocket!==0?"checked":""}> WebSocket</label><label><input name="ssl_enabled" type="checkbox" ${host?.ssl_enabled?"checked":""}> SSL aktivieren</label><label><input name="enabled" type="checkbox" ${host?.enabled!==0?"checked":""}> Host aktiv</label></div><div class="real-card-head"><div><h2>Upstream-Ziele</h2><p>IPv4, IPv6 und Hostnamen können gemischt werden.</p></div><button type="button" class="button" id="modalAddTarget">＋ Ziel</button></div><div class="host-targets" id="modalTargets">${targets.map(modalTargetRow).join("")}</div><div class="host-modal-actions"><button type="button" class="button" id="cancelHostModal">Abbrechen</button><button class="button primary">Speichern und aktivieren</button></div>`;
  const targetBox=form.querySelector("#modalTargets"); form.querySelector("#modalAddTarget").onclick=()=>targetBox.insertAdjacentHTML("beforeend",modalTargetRow({address:"",family:"IPv4",weight:100,mode:"active"})); targetBox.onclick=event=>{if(event.target.classList.contains("modal-remove-target")&&targetBox.children.length>1)event.target.closest(".host-target-row").remove()}; form.querySelector("#cancelHostModal").onclick=()=>dialog.close();
  form.onsubmit=async event=>{event.preventDefault();const values=Object.fromEntries(new FormData(form));const healthPath=(values.health_path||"/").trim()||"/";const payload={id:host?.id,domain:values.domain.trim(),scheme:values.scheme,port:Number(values.port),strategy:values.strategy,certificate_id:Number(values.certificate_id)||null,websocket:form.elements.websocket.checked,ssl_enabled:form.elements.ssl_enabled.checked,enabled:form.elements.enabled.checked,targets:[...targetBox.querySelectorAll(".host-target-row")].map(row=>({address:row.querySelector('[name="target_address"]').value.trim(),family:row.querySelector('[name="target_family"]').value,weight:Number(row.querySelector('[name="target_weight"]').value),mode:row.querySelector('[name="target_mode"]').value,health_path:healthPath}))};try{await api("/api/proxy-hosts",{method:"POST",body:JSON.stringify(payload)});await api("/api/apply",{method:"POST",body:"{}"});dialog.close();await showHostOverview();toast("Proxy Host gespeichert",payload.domain)}catch(error){toast("Speichern fehlgeschlagen",error.message)}};
  dialog.showModal();
}
function modalTargetRow(target){const family=target.family==="hostname"?"Hostname":target.family;return `<div class="host-target-row"><input name="target_address" value="${escapeHtml(target.address||"")}" placeholder="192.168.1.20 oder 2001:db8::20" required><select name="target_family"><option ${family==="IPv4"?"selected":""}>IPv4</option><option ${family==="IPv6"?"selected":""}>IPv6</option><option ${family==="Hostname"?"selected":""}>Hostname</option></select><input name="target_weight" type="number" min="1" max="100" value="${target.weight||100}"><select name="target_mode"><option value="active" ${target.mode==="active"?"selected":""}>Aktiv</option><option value="backup" ${target.mode==="backup"?"selected":""}>Backup</option><option value="off" ${target.mode==="off"?"selected":""}>Aus</option></select><button type="button" class="button modal-remove-target">×</button></div>`}
document.querySelector("#closeHostDialog").onclick=()=>document.querySelector("#hostDialog").close();

async function saveHost() {
  try {
    const healthPath = document.querySelector("#healthPath").value.trim() || "/";
    const payload = { id: state.hostId, domain: document.querySelector("#domain").value.trim(), scheme: document.querySelector("#scheme").value, port: Number(document.querySelector("#port").value), strategy: document.querySelector("#strategy").value, websocket: document.querySelector("#websocket").checked, ssl_enabled: document.querySelector("#sslEnabled").checked, certificate_id: Number(document.querySelector("#certificateSelect").value) || null, enabled: true, targets: state.targets.map(target => ({ address: target.address.trim(), family: target.family, weight: Number(target.weight), mode: target.mode === "Backup" ? "backup" : target.mode === "Aus" ? "off" : "active", health_path: healthPath })) };
    const result = await api("/api/proxy-hosts", { method: "POST", body: JSON.stringify(payload) }); state.hostId = result.id;
    await api("/api/apply", { method: "POST", body: "{}" }); toast("Gespeichert und aktiviert", "Nginx übernimmt die geprüfte Konfiguration automatisch.");
  } catch (error) { toast("Speichern fehlgeschlagen", error.message); }
}

function applyAccount(user) {
  if (!user) return;
  state.role = user.role;
  document.querySelector("#accountName").textContent = user.username;
  document.querySelector("#accountRole").textContent = ({ admin: "Administrator", operator: "Operator", viewer: "Betrachter" })[user.role] || user.role;
  document.querySelector("#updateButton").hidden = user.role !== "admin";
  document.querySelector("#usersLink").hidden = user.role !== "admin";
  document.querySelector("#accountAvatar").textContent = user.username.slice(0, 2).toUpperCase();
  document.querySelector("#loginUser").value = user.username;
}

document.querySelector("#loginForm").addEventListener("submit", async event => {
  event.preventDefault(); const errorBox = document.querySelector("#loginError"); errorBox.textContent = "";
  try { const data = await api("/api/login", { method: "POST", body: JSON.stringify({ username: document.querySelector("#loginUser").value, password: document.querySelector("#loginPassword").value }) }); state.csrf = data.csrf; startIdleLogout(); applyAccount(data.user); const loginScreen=document.querySelector("#loginScreen"); loginScreen.classList.add("closing"); await new Promise(resolve=>setTimeout(resolve,900)); loginScreen.classList.add("hidden"); loginScreen.classList.remove("closing"); await loadHosts(); await showRealDashboard(); }
  catch (error) { errorBox.textContent = error.message; const card=document.querySelector(".login-card");card.classList.remove("login-denied");void card.offsetWidth;card.classList.add("login-denied"); }
});

async function restoreSession() {
  try { const data = await api("/api/session"); state.csrf = data.csrf; applyAccount(data.user); document.querySelector("#loginScreen").classList.add("hidden"); startIdleLogout(); await loadHosts(); await showRealDashboard(); }
  catch { renderTargets(); }
}

let idleLogoutTimer=0,lastActivity=Date.now(),lastActivitySync=0;
function stopIdleLogout(){clearTimeout(idleLogoutTimer);idleLogoutTimer=0}
function startIdleLogout(){lastActivity=Date.now();stopIdleLogout();idleLogoutTimer=setTimeout(checkIdleLogout,600000)}
function registerActivity(){if(!state.csrf)return;lastActivity=Date.now();clearTimeout(idleLogoutTimer);idleLogoutTimer=setTimeout(checkIdleLogout,600000);if(Date.now()-lastActivitySync>60000){lastActivitySync=Date.now();api("/api/session/activity",{method:"POST",body:"{}"}).catch(()=>{})}}
function checkIdleLogout(){const remaining=600000-(Date.now()-lastActivity);if(remaining>0){idleLogoutTimer=setTimeout(checkIdleLogout,remaining);return}performLogout(true)}
async function performLogout(automatic=false){
  const loginScreen=document.querySelector("#loginScreen");loginScreen.classList.remove("hidden");loginScreen.classList.add("opening");
  try{await api("/api/logout",{method:"POST",body:"{}"})}catch{}
  state.csrf="";stopIdleLogout();
  document.querySelector("#loginPassword").value="";
  setTimeout(()=>{loginScreen.classList.remove("opening");if(automatic){const error=document.querySelector("#loginError");error.textContent="Du wurdest nach 10 Minuten Inaktivität automatisch abgemeldet."}},900);
}
document.querySelector("#logoutButton").addEventListener("click",()=>performLogout(false));
["pointerdown","keydown","touchstart","scroll"].forEach(eventName=>window.addEventListener(eventName,registerActivity,{passive:true}));
document.addEventListener("visibilitychange",()=>{if(!document.hidden&&state.csrf)checkIdleLogout()});

const managerDialog = document.querySelector("#managerDialog");
document.querySelector("#closeManager").addEventListener("click", () => { clearTimeout(updatePollTimer); managerDialog.close(); managerDialog.classList.remove("update-dialog"); });
document.querySelector("#dnsHelpButton").addEventListener("click",async()=>{const settings=await api("/api/branding");document.querySelector("#managerTitle").textContent="DNS-Anleitung";document.querySelector("#managerSubtitle").textContent="Records beim DNS-Anbieter eintragen";document.querySelector("#managerContent").innerHTML=`<div class="dns-guide"><p>Lege für deine Proxy-Domain die folgenden Records an. Als Name verwendest du je nach Anbieter die vollständige Domain oder nur den Host-Anteil.</p><div><span class="record">A</span><code>${escapeHtml(settings.gateway_ipv4||"Zuerst Gateway-IPv4 unter Einstellungen eintragen")}</code></div><div><span class="record purple">AAAA</span><code>${escapeHtml(settings.gateway_ipv6||"Optional: Gateway-IPv6 unter Einstellungen eintragen")}</code></div><p>Die DNS-Adressen müssen auf den Server beziehungsweise Router zeigen, der TCP 80 und 443 an ProxyManagerDeck2 weiterleitet.</p></div>`;managerDialog.showModal()});
