const certificateObserver = new MutationObserver(async () => {
  const form = document.querySelector("#certForm");
  if (!form || form.dataset.enhanced) return;
  form.dataset.enhanced = "1";
  const embeddedProviderForm = document.querySelector("#providerForm");
  if (embeddedProviderForm) {
    embeddedProviderForm.outerHTML = '<div class="provider-hint"><div><strong>DNS-Zugangsdaten getrennt verwalten</strong><small>API-Schlüssel und Anbieter-Einstellungen befinden sich übersichtlich unter DNS-Plugins.</small></div><button class="button" id="openDnsPlugins" type="button">DNS-Plugins öffnen</button></div>';
    document.querySelector("#openDnsPlugins").onclick = () => { managerDialog.close(); document.querySelector('[data-manager="providers"]').click(); };
  }
  const domainInput = form.elements.domain;
  if (domainInput) {
    const label = domainInput.closest("label");
    label.classList.add("wide");
    label.innerHTML = '<span>Domains / SANs</span><input name="domains" type="hidden"><div class="certificate-domains" id="certificateDomains"><div class="certificate-domain-row"><input class="certificate-domain" placeholder="example.com" required><button class="button certificate-domain-remove" type="button">×</button></div></div><button class="button certificate-domain-add" id="certificateDomainAdd" type="button">＋ Domain hinzufügen</button><small>Für jede Domain eine eigene Zeile. Wildcards wie *.example.com benötigen DNS-01.</small>';
    const domainList = label.querySelector("#certificateDomains"), hiddenDomains = form.elements.domains;
    const syncDomains = () => { hiddenDomains.value = [...domainList.querySelectorAll(".certificate-domain")].map(input => input.value.trim()).filter(Boolean).join(","); if (hiddenDomains.value.includes("*.")) challenge.value = "dns-01"; };
    label.querySelector("#certificateDomainAdd").onclick = () => { domainList.insertAdjacentHTML("beforeend", '<div class="certificate-domain-row"><input class="certificate-domain" placeholder="www.example.com" required><button class="button certificate-domain-remove" type="button">×</button></div>'); domainList.lastElementChild.querySelector("input").focus(); };
    domainList.addEventListener("click", event => { if (event.target.classList.contains("certificate-domain-remove") && domainList.children.length > 1) { event.target.closest(".certificate-domain-row").remove(); syncDomains(); } });
    domainList.addEventListener("input", syncDomains);
    form.addEventListener("submit", syncDomains, true);
  }
  const challenge = form.elements.challenge;
  challenge.options[1].textContent = "DNS-01 (für Wildcards)";
  try {
    const certificates = (await api("/api/certificates")).items;
    const list = form.parentElement.querySelector(".manager-list");
    const statusNames = { issued: "Gültig", requesting: "Wird angefordert", failed: "Fehler", pending: "Ausstehend" };
    list.innerHTML = certificates.map(certificate => {
      let domains;
      try { domains = JSON.parse(certificate.domains_json || "null") || [certificate.domain]; } catch { domains = [certificate.domain]; }
      const detail = certificate.status === "failed" ? certificate.last_error || "ACME-Anforderung fehlgeschlagen" : certificate.expires_at ? `Gültig bis ${new Date(certificate.expires_at * 1000).toLocaleDateString("de-DE")}` : "Kein Ablaufdatum gemeldet";
      return `<div class="manager-row"><div><strong>${domains.map(escapeHtml).join(" · ")}</strong><small>${escapeHtml(certificate.email)} · ${escapeHtml((certificate.challenge || "http-01").toUpperCase())}</small></div><span class="tag">${escapeHtml(statusNames[certificate.status] || certificate.status)}</span><small>${escapeHtml(detail)}</small></div>`;
    }).join("") || '<div class="empty-state">Noch keine Zertifikate vorhanden.</div>';
  } catch (error) { toast("Zertifikate nicht geladen", error.message); }
});
certificateObserver.observe(document.querySelector("#managerContent"), { childList: true });

const dnsProviderObserver = new MutationObserver(async () => {
  const form=document.querySelector("#dnsPluginForm");if(!form||form.dataset.structured)return;form.dataset.structured="1";
  const providers=(await api("/api/acme-providers")).items;
  const idLabel=document.createElement("label");idLabel.innerHTML=`<span>Plugin anlegen oder bearbeiten</span><select name="id"><option value="">Neues DNS-Plugin</option>${providers.map(provider=>`<option value="${provider.id}">${escapeHtml(provider.name)} · ${escapeHtml(provider.provider)}</option>`).join("")}</select>`;form.prepend(idLabel);
  const primary=form.elements.primary.closest("label"),secondary=form.elements.secondary.closest("label"),tertiary=form.elements.tertiary.closest("label");
  const definitions={cloudflare:[["API-Token",true],["",false],["",false]],digitalocean:[["API-Token",true],["",false],["",false]],route53:[["Access Key ID",true],["Secret Access Key",true],["",false]],ionos:[["API-Token",true],["",false],["",false]],hetzner:[["DNS API-Token",true],["",false],["",false]],ipv64:[["API-Token",true],["",false],["",false]],strato:[["Benutzername",true],["Passwort",true],["",false]],powerdns:[["PowerDNS API-URL",true],["Server-ID",true],["PowerDNS API-Token",true]]};
  const sync=()=>{const fields=[primary,secondary,tertiary],definition=definitions[form.elements.provider.value];fields.forEach((label,index)=>{const [title,visible]=definition[index];label.hidden=!visible;label.querySelector("span").textContent=title;label.querySelector("input").required=visible});};form.elements.provider.addEventListener("change",sync);sync();
  form.elements.id.addEventListener("change",()=>{const selected=providers.find(provider=>provider.id===Number(form.elements.id.value));if(selected){form.elements.name.value=selected.name;form.elements.provider.value=selected.provider;sync()}else{form.elements.name.value=""}});
  form.addEventListener("submit",async event=>{event.preventDefault();event.stopImmediatePropagation();const values=Object.fromEntries(new FormData(form));let credentials;if(["cloudflare","ionos","hetzner","ipv64"].includes(values.provider))credentials={api_token:values.primary};else if(values.provider==="digitalocean")credentials={token:values.primary};else if(values.provider==="route53")credentials={access_key_id:values.primary,secret_access_key:values.secondary};else if(values.provider==="strato")credentials={username:values.primary,password:values.secondary};else credentials={api_url:values.primary,server_id:values.secondary,api_token:values.tertiary};try{await api("/api/acme-providers",{method:"POST",body:JSON.stringify({id:values.id?Number(values.id):undefined,name:values.name,provider:values.provider,credentials,current_password:values.current_password})});managerDialog.close();toast("DNS-Plugin gespeichert",values.name)}catch(error){toast("Plugin nicht gespeichert",error.message)}},true);
});
dnsProviderObserver.observe(document.querySelector("#managerContent"),{childList:true});

const brandingObserver=new MutationObserver(async()=>{const form=document.querySelector("#brandingForm");if(!form||form.dataset.scaling)return;form.dataset.scaling="1";const settings=await api("/api/branding"),scaleLabel=document.createElement("label");scaleLabel.innerHTML=`<span>Größe der Oberfläche</span><select name="ui_scale"><option value="0.5" ${String(settings.ui_scale)==="0.5"?"selected":""}>0,5× · Kompakt</option><option value="1" ${!["0.5","1.5"].includes(String(settings.ui_scale))?"selected":""}>1,0× · Standard</option><option value="1.5" ${String(settings.ui_scale)==="1.5"?"selected":""}>1,5× · Groß</option></select>`;form.insertBefore(scaleLabel,form.querySelector("button"));form.addEventListener("submit",async event=>{event.preventDefault();event.stopImmediatePropagation();try{const logo=await readImage(form.logo_file),favicon=await readImage(form.favicon_file),payload={accent:form.accent.value,background:form.background.value,gateway_ipv4:form.gateway_ipv4.value,gateway_ipv6:form.gateway_ipv6.value,logo:logo||settings.logo||"",favicon:favicon||settings.favicon||"",ui_scale:form.ui_scale.value};await api("/api/branding",{method:"POST",body:JSON.stringify(payload)});applyBranding(payload);managerDialog.close();toast("Design gespeichert",`Oberfläche auf ${form.ui_scale.options[form.ui_scale.selectedIndex].text.split(" · ")[0]} skaliert.`)}catch(error){toast("Design nicht gespeichert",error.message)}},true)},);
brandingObserver.observe(document.querySelector("#managerContent"),{childList:true});

